class Stack<T> {
  final List<T> _items = [];

  bool get isEmpty => _items.isEmpty;
  int get length => _items.length;

  // Push - O(1) amortized
  void push(T item) {
    _items.add(item);
  }

  // Pop - O(1)
  T pop() {
    if (isEmpty) throw StateError('Stack is empty');
    return _items.removeLast();
  }

  // Peek - O(1)
  T peek() {
    if (isEmpty) throw StateError('Stack is empty');
    return _items.last;
  }

  @override
  String toString() => _items.toString();
}

// Usage
var stack = Stack<int>();
stack.push(1);
stack.push(2);
stack.push(3);
print(stack.peek()); // 3
print(stack.pop());  // 3
print(stack);        // [1, 2]
```

